xh(8) = check_K(xr{8}, PB.K8_labels, PB.K8_embed, 'x8');
xh(9) = check_D(xr{9}, PB.D9_vals, 'x9');
tmp = check_C(xr{10}, PB.lb_C_work(10), PB.ub_C_work(10), 'x10');
xh(10) = map_C_to_orig(tmp, PB.lb_C_work(10), PB.ub_C_work(10), PB.lb_orig(10), PB.ub_orig(10));
xh(11) = check_D(xr{11}, PB.D11_vals, 'x11');
xh(12) = check_K(xr{12}, PB.K12_labels, PB.K12_embed, 'x12');
tmp = check_C(xr{13}, PB.lb_C_work(13), PB.ub_C_work(13), 'x13');
xh(13) = map_C_to_orig(tmp, PB.lb_C_work(13), PB.ub_C_work(13), PB.lb_orig(13), PB.ub_orig(13));
xh(14) = check_K(xr{14}, PB.K14_labels, PB.K14_embed, 'x14');
xh(15) = check_D(xr{15}, PB.D15_vals, 'x15');
tmp = check_C(xr{16}, PB.lb_C_work(16), PB.ub_C_work(16), 'x16');
xh(16) = map_C_to_orig(tmp, PB.lb_C_work(16), PB.ub_C_work(16), PB.lb_orig(16), PB.ub_orig(16));
xh(17) = check_D(xr{17}, PB.D17_vals, 'x17');
xh(18) = check_K(xr{18}, PB.K18_labels, PB.K18_embed, 'x18');
tmp = check_C(xr{19}, PB.lb_C_work(19), PB.ub_C_work(19), 'x19');
xh(19) = map_C_to_orig(tmp, PB.lb_C_work(19), PB.ub_C_work(19), PB.lb_orig(19), PB.ub_orig(19));
xh(20) = check_K(xr{20}, PB.K20_labels, PB.K20_embed, 'x20');
xh(21) = check_D(xr{21}, PB.D21_vals, 'x21');
tmp = check_C(xr{22}, PB.lb_C_work(22), PB.ub_C_work(22), 'x22');
xh(22) = map_C_to_orig(tmp, PB.lb_C_work(22), PB.ub_C_work(22), PB.lb_orig(22), PB.ub_orig(22));
end

function v = check_C(val, a, b, name)
if ~isnumeric(val) || ~isscalar(val) || ~isreal(val)
    error('DTLZ6_mix: %s must be a real scalar.', name);
end
if val < a || val > b
    error('DTLZ6_mix: %s=%g outside [%g,%g].', name, val, a, b);
end
v = double(val);
end

function xorig = map_C_to_orig(xwork, lbw, ubw, lbo, ubo)
if abs(ubw - lbw) <= 1e-14
    t = 0;
else
    t = (xwork - lbw) / (ubw - lbw);
end
t = max(0, min(1, t));
xorig = lbo + t * (ubo - lbo);
end

function v = check_D(val, grid, name)
if ~isnumeric(val) || ~isscalar(val) || ~isreal(val)
    error('DTLZ6_mix: %s must be a real scalar.', name);
end
grid = grid(:);
[dmin, idx] = min(abs(grid - val));
if dmin > 1e-10 * max(1, max(abs(grid)))
    error('DTLZ6_mix: %s=%g not in grid.', name, val);
end
v = grid(idx);
end

function v = check_K(label, labels, embed, name)
if isstring(label), label = char(label); end
if ~(ischar(label) && isrow(label))
    error('DTLZ6_mix: %s must be a char vector or scalar string.', name);
end
idx = find(strcmp(label, labels), 1);
if isempty(idx)
    error('DTLZ6_mix: %s unknown label ''%s''.', name, label);
end
v = embed(idx);
end


% -------------------------------------------------------------------------
% Embedded original continuous MOO problem (top-level function renamed only)
% -------------------------------------------------------------------------
function f = DTLZ6_orig(x)
%###############################################################################
%
%   As described by K. Deb, L. Thiele, M. Laumanns and E. Zitzler in "Scalable
%   Multi-Objective Optimization Test Problems", Congress on Evolutionary 
%   Computation (CEC'2002): 825-830, 2002.
%
%   Example DTLZ6.
%
%   This file is part of a collection of problems developed for
%   derivative-free multiobjective optimization in
%   A. L. CustÃ³dio, J. F. A. Madeira, A. I. F. Vaz, and L. N. Vicente,
%   Direct Multisearch for Multiobjective Optimization, 2010.
%
%   Written by the authors in June 1, 2010.
%
%   MATLAB version by J. F. A. Madeira
%   November 7, 2025
%
%###############################################################################
%
% Problem characteristics:
% - Number of variables: n >= M (default n = 22 for M = 3)
% - Number of objectives: M >= 2 (default M = 3)
%   Bounds: x1 in [0,1], x2 in [0,1], x3 in [0,1], x4 in [0,1], x5 in [0,1], x6 in [0,1], x7 in [0,1], x8 in [0,1], x9 in [0,1], x10 in [0,1], x11 in [0,1], x12 in [0,1], x13 in [0,1], x14 in [0,1], x15 in [0,1], x16 in [0,1], x17 in [0,1], x18 in [0,1], x19 in [0,1], x20 in [0,1], x21 in [0,1], x22 in [0,1]
%
%
% Fixed parameters for DTLZ6
M = 3;  % Number of objectives (fixed)
n = length(x);
% Check minimum dimension
if n < M
    error('DTLZ6 requires n >= M, but n = %d and M = %d', n, M);
end
% Calculate k (number of variables in g function)
k = n - M + 1;
% Ensure x is a column vector
x = x(:);
% Initialize objectives
f = zeros(M, 1);
% Calculate g(x)
sum_term = 0;
for i = M:n
    sum_term = sum_term + x(i);
end
gx = 1 + (9/k) * sum_term;
% Calculate objectives
% f1 to f(M-1)
for i = 1:(M-1)
    f(i) = x(i);
end
% fM
sum_term = 0;
for i = 1:(M-1)
    sum_term = sum_term + (x(i)/(1 + gx)) * (1 + sin(3*pi*x(i)));
end
f(M) = (1 + gx) * (M - sum_term);
end

